#include <stdio.h>
#include <string.h>

char stack[100];
int top = -1;

void push(char c) {
    stack[++top] = c;
}

char pop() {
    return stack[top--];
}

int main() {
    char prefix[100];
    printf("Enter prefix expression: ");
    scanf("%s", prefix);
    int n = strlen(prefix);
    for (int i = n - 1; i >= 0; i--) {
        if (prefix[i] == '+' || prefix[i] == '-' || prefix[i] == '*' || prefix[i] == '/') {
            char op1 = pop();
            char op2 = pop();
            printf("%c%c%c", op1, op2, prefix[i]);
        } else {
            push(prefix[i]);
        }
    }
    return 0;
}

